<script>
   var isAnyModalOpen = false;
    $('#exampleModal-4').on('shown.bs.modal', function () {
        isAnyModalOpen = true;
    });
    
    $('#exampleModal-4').on('hidden.bs.modal', function () {
        isAnyModalOpen = false;
    });
  document.addEventListener("DOMContentLoaded", function() {
    setTimeout(function() {
      var myModal = new bootstrap.Modal(document.getElementById('exampleModal_new'));
      if (!isAnyModalOpen) {
        myModal.show();
      }
    }, 2000); // 2000ms = 2 seconds
  });
  $('.Home_slider_new_sec').on('initialized.owl.carousel', function() {
        $('.Home_slider_new_sec, .custom_arrow').fadeIn();
